import React, {useEffect, useState} from 'react';
import axios from 'axios';
import {Link, useSearchParams} from 'react-router';
import {useLoaderData} from 'react-router-dom';

const Users = () => {
    const users = useLoaderData();
    const [queryParams, setQueryParams] = useSearchParams({});
    const [searchText, setSearchText] = useState(queryParams.get('q'));

    const handleSearch = (e) =>{
        setSearchText(e.target.value);
        setQueryParams({q: e.target.value});
    }

    const filteredUsers = (user) => {
        return searchText.trim() === "" ? true : user.name.toLowerCase().includes(searchText.toLowerCase());
    }

    return (
        <div>
            <h1>Users</h1>

            <input type="text" value={searchText} onChange={handleSearch} className="border"/>

            {users.filter(user => user.name.includes(searchText)).map(user => <div key={user.id}>
                <Link to={`/users/${user.id}`}>{user.name}</Link>
            </div>)}
        </div>
    );
}

export default Users;
